import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';

// Pages Import
import Home from './pages/Home';
import Services from './pages/Services';
import Registration from './pages/Registration';
import Login from './pages/Login'; 
import AdminDashboard from './pages/Admin'; 
import ClientDashboard from './pages/ClientDashboard';
import Contact from './pages/Contact'; 
import FreelancerProfile from './pages/FreelancerProfile'; 

// Bootstrap CSS
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [user, setUser] = useState(null);
  // 1. State for Dark Mode
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setUser(JSON.parse(loggedInUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setUser(null);
    alert("Logged out successfully!");
    window.location.href = "/"; 
  };

  // 2. Function to toggle Dark Mode
  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
  };

  return (
    <Router>
      {/* 3. Dynamic background based on darkMode state */}
      <div className={`App d-flex flex-column min-vh-100 ${darkMode ? 'bg-dark-mode text-white' : 'bg-light text-dark'}`}>
        
        {/* Navigation Bar */}
        <nav className={`navbar navbar-expand-lg sticky-top py-2 shadow ${darkMode ? 'navbar-dark bg-black border-bottom border-secondary' : 'navbar-dark bg-dark'}`}>
          <div className="container">
            <Link className="navbar-brand fw-bold fs-3" to="/">
              Freelancer<span className="text-primary"> Hub</span>
            </Link>
            
            <button className="navbar-toggler border-0" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
              <span className="navbar-toggler-icon"></span>
            </button>
            
            <div className="collapse navbar-collapse" id="navbarNav">
              {/* Menu Links */}
              <ul className="navbar-nav mx-auto align-items-center gap-3">
                <li className="nav-item"><Link className="nav-link text-white" to="/">Home</Link></li>
                <li className="nav-item"><Link className="nav-link text-white" to="/services">Services</Link></li>
                <li className="nav-item"><Link className="nav-link text-info fw-semibold" to="/client-dashboard">Dashboard</Link></li>
                <li className="nav-item"><Link className="nav-link text-warning fw-semibold" to="/admin">Admin</Link></li>
              </ul>

              {/* Right Side: Mode Toggle & Profile */}
              <div className="navbar-nav ms-auto align-items-center gap-3">
                
                {/* 4. Dark Mode Toggle Button */}
                <button onClick={toggleDarkMode} className={`btn btn-sm rounded-pill px-3 fw-bold ${darkMode ? 'btn-outline-warning' : 'btn-outline-info'}`}>
                  {darkMode ? '☀️ Light' : '🌙 Dark'}
                </button>

                {/* Profile Avatar Widget */}
                <Link to="/profile/1" className="d-flex align-items-center text-decoration-none border border-secondary rounded-pill p-1 pe-3 hover-effect">
                    <div className="position-relative">
                        <div 
                          className="rounded-circle border border-2 border-primary d-flex align-items-center justify-content-center fw-bold text-white shadow-sm"
                          style={{ width: '35px', height: '35px', background: '#1e3c72', fontSize: '1rem' }}
                        >
                          R
                        </div>
                        <span className="position-absolute bottom-0 end-0 bg-success border border-1 border-white rounded-circle" style={{ width: '10px', height: '10px' }}></span>
                    </div>
                    <div className="ms-2 d-none d-lg-block text-start">
                        <p className="text-white mb-0 small fw-bold" style={{ lineHeight: '1' }}>Rahul Patil</p>
                        <small className="text-primary" style={{ fontSize: '9px' }}>Available</small>
                    </div>
                </Link>

                {!user ? (
                  <Link className="btn btn-sm btn-primary rounded-pill px-3 ms-2 fw-bold shadow-sm" to="/login">Login</Link>
                ) : (
                  <button onClick={handleLogout} className="btn btn-sm btn-danger rounded-pill px-3 ms-2 fw-bold shadow-sm">Logout</button>
                )}
              </div>
            </div>
          </div>
        </nav>

        {/* Main Content Area */}
        <main className="flex-grow-1">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/services" element={<Services />} />
            <Route path="/register" element={<Registration />} />
            <Route path="/login" element={<Login />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/client-dashboard" element={<ClientDashboard />} />
            <Route path="/contact" element={<Contact />} /> 
            <Route path="/profile/:id" element={<FreelancerProfile />} />
          </Routes>
        </main>

        {/* Footer Area */}
        <footer className={`${darkMode ? 'bg-black border-top border-secondary text-secondary' : 'bg-dark text-white'} py-3 text-center mt-auto`}>
          <small className="opacity-50">© 2026 Freelancer Hub | Nashik, India</small>
        </footer>

        {/* Internal CSS for Dark Mode Integration */}
        <style>{`
            .bg-dark-mode { background-color: #121212 !important; color: white !important; }
            .bg-black { background-color: #000000 !important; }
            .hover-effect:hover { background: rgba(255,255,255,0.1); transition: 0.3s; }
            
            /* Apply Dark Mode styles to cards and global elements */
            .bg-dark-mode .card { background-color: #1e1e1e !important; color: white !important; border-color: #333 !important; }
            .bg-dark-mode .text-muted { color: #aaa !important; }
            .bg-dark-mode .bg-white { background-color: #1e1e1e !important; color: white !important; }
            .bg-dark-mode .bg-light { background-color: #181818 !important; }
            .bg-dark-mode .feature-box, .bg-dark-mode .feedback-card { background-color: #252525 !important; border-color: #444 !important; }
            
            /* Ensure links are readable in dark mode */
            .bg-dark-mode .nav-link:hover { color: #ffc107 !important; }
        `}</style>
      </div>
    </Router>
  );
}

export default App;
